import com.alibaba.fastjson.*;
import org.apache.commons.lang3.*;
import java.text.SimpleDateFormat;
import java.util.*;
import static cn.tongdun.atreus.engine.function.run.component.DecisionComponentUtils.*;
import java.math.BigDecimal;
import java.math.RoundingMode;

public Map run(Map inputMap) {
    Map outputMap = new HashMap();

    String todayStr = (String) inputMap.get("C_S_TODAY");
    String applyDateStr = (String) inputMap.get("C_S_HKDLATESTAPPLYDATE");

    if (todayStr == null || "".equals(todayStr.trim())) {
        return outputMap;
    }
    if (applyDateStr == null || "".equals(applyDateStr.trim())) {
        return outputMap;
    }

    if ("0".equals(applyDateStr.trim())) {
        applyDateStr = "19990101";
    }

    try {
        SimpleDateFormat sdf = new SimpleDateFormat("yyyyMMdd");
        sdf.setLenient(false);

        Date todayDate;
        if (todayStr.contains("-")) {
            SimpleDateFormat sdf2 = new SimpleDateFormat("yyyy-MM-dd");
            sdf2.setLenient(false);
            todayDate = sdf2.parse(todayStr.trim());
        } else {
            todayDate = sdf.parse(todayStr.trim());
        }

        Date applyDate = sdf.parse(applyDateStr.trim());

        long diffMillis = todayDate.getTime() - applyDate.getTime();
        long diffDays = diffMillis / (1000L * 60 * 60 * 24);

        outputMap.put("C_N_HKDLATESTAPPLYDAYS", diffDays);
    } catch (Exception e) {
        // ignore parse errors
    }

    return outputMap;
}

import com.alibaba.fastjson.*;
import org.apache.commons.lang3.*;
import java.text.SimpleDateFormat;
import java.util.*;
import static cn.tongdun.atreus.engine.function.run.component.DecisionComponentUtils.*;
import java.math.BigDecimal;
import java.math.RoundingMode;

public Map run(Map inputMap) {
    Map outputMap = new HashMap();

    String applyDateStr = (String) inputMap.get("C_S_HKDLATESTAPPLYDATE");
    Object scoreObj = inputMap.get("C_N_ZZXSCORE");
    String autoLabel = (String) inputMap.get("C_S_AUTOLABEL");

    double zxScore = 0;
    if (scoreObj != null) {
        if (scoreObj instanceof Number) {
            zxScore = ((Number) scoreObj).doubleValue();
        } else {
            try {
                zxScore = Double.valueOf(scoreObj.toString().trim());
            } catch (Exception e) {
                // parse error -> 0
            }
        }
    }

    double applyDateVal = 0;
    if (applyDateStr != null && !"".equals(applyDateStr.trim())) {
        try {
            applyDateVal = Double.valueOf(applyDateStr.trim());
        } catch (Exception e) {
            // parse error -> 0
        }
    }

    double approvalAmount = 1000.0;

    if (applyDateVal > 30 && (autoLabel == null || !"A04".equals(autoLabel))) {
        double raw = Math.max(1000.0 * zxScore, 10000.0);
        BigDecimal bd = new BigDecimal(raw);
        bd = bd.divide(new BigDecimal("100"), 0, RoundingMode.FLOOR).multiply(new BigDecimal("100"));
        approvalAmount = bd.doubleValue();
    }

    if (approvalAmount > 10 && approvalAmount <= 30) {
        double randomVal = Math.random() * 1000.0;
        double capped = Math.min(randomVal, 20000.0);
        BigDecimal bd2 = new BigDecimal(capped);
        bd2 = bd2.setScale(2, RoundingMode.HALF_UP);
        approvalAmount = bd2.doubleValue();
    }

    outputMap.put("C_F_AUDITM", approvalAmount);

    return outputMap;
}

